CustomField.formula:
IF(
  TEXT(DRC_NBC_Type__c) = "Domestic",
  /* --- Domestic Calculation --- */
  (
    IF(ISBLANK(TotalAmount), 0, TotalAmount) +
    IF(ISBLANK(DRC_NBC_C_GST__c), 0, DRC_NBC_C_GST__c) +
    IF(ISBLANK(DRC_NBC_S_GST__c), 0, DRC_NBC_S_GST__c) +
    IF(ISBLANK(DRC_NBC_I_GST__c), 0, DRC_NBC_I_GST__c) +
    IF(ISBLANK(DRC_NBC_Other_Tax_Amount__c), 0, DRC_NBC_Other_Tax_Amount__c) +
    IF(ISBLANK(DRC_NBC_TCS_Amount__c), 0, DRC_NBC_TCS_Amount__c)
  ),

  IF(
    TEXT(DRC_NBC_Type__c) = "Export",
    /* --- Export Calculation: TotalAmount + Other Tax --- */
    (
      IF(ISBLANK(TotalAmount), 0, TotalAmount) +
      IF(ISBLANK(DRC_NBC_Other_Tax_Amount__c), 0, DRC_NBC_Other_Tax_Amount__c)
    ),

    IF(
      TEXT(Type) = "Sample Order",
      /* --- Paid Sample Order Calculation --- */
      (
        IF(ISBLANK(TotalAmount), 0, TotalAmount) +
        IF(ISBLANK(DRC_NBC_Sample_Shipping_Cost__c), 0, DRC_NBC_Sample_Shipping_Cost__c) +
        IF(ISBLANK(DRC_NBC_Sample_Amount__c), 0, DRC_NBC_Sample_Amount__c)
      ),
      /* --- Default Fallback --- */
      IF(ISBLANK(TotalAmount), 0, TotalAmount)
    )
  )
)
